code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Button, icon } from 'decantr/components';

code.example:
function CtaSection() {
  const { section, h2, p, div } = tags;

  return section({ class: css('_flex _col _items[center] _text[center] _py12 _px4 _gap4') },
    h2({ class: css('_heading2') }, 'Ready to Get Started?'),
    p({ class: css('_body _fgmuted _mw[640px]') }, 'Join thousands of developers building better applications faster with our platform.'),
    div({ class: css('_flex _gap3') },
      Button({ variant: 'primary', size: 'lg' }, 'Start Free Trial'),
      Button({ variant: 'outline', size: 'lg' }, 'Learn More')
    )
  );
}

