function CtaSectionSplit() {
  const { section, div, h2, p, img } = tags;

  return section({ class: css('_grid _gc1 _lg:gc2 _gap6 _items[center] _py8') },
    div({ class: css('_flex _col _gap4') },
      h2({ class: css('_heading2') }, 'Take Your Project to the Next Level'),
      p({ class: css('_body _fgmuted') }, 'Our platform provides everything you need to build, deploy, and scale your applications with confidence.'),
      div({ class: css('_flex _gap3') },
        Button({ variant: 'primary', size: 'lg' }, 'Get Started'),
        Button({ variant: 'ghost', size: 'lg' }, icon('arrow-right'), 'See Examples')
      )
    ),
    img({ src: '/images/cta-illustration.svg', alt: 'Platform illustration', class: css('_wfull _rounded') })
  );
}

